import{_ as a,c as o,o as t,a1 as r}from"./chunks/framework.DILC4Csi.js";const p=JSON.parse('{"title":"Gestión de cuotas: Quota Protection y calentamiento | Antigravity-Manager","description":"Aprende el mecanismo de gestión de cuotas de Antigravity-Manager. Usa Quota Protection para proteger modelos por umbral, Smart Warmup para calentamiento automático, soporta escaneo programado y control de enfriamiento.","frontmatter":{"title":"Gestión de cuotas: Quota Protection y calentamiento | Antigravity-Manager","subtitle":"Gestión de cuotas: Quota Protection y calentamiento | Antigravity-Manager","sidebarTitle":"Protege las cuotas de tus modelos","description":"Aprende el mecanismo de gestión de cuotas de Antigravity-Manager. Usa Quota Protection para proteger modelos por umbral, Smart Warmup para calentamiento automático, soporta escaneo programado y control de enfriamiento.","tags":["cuota","calentamiento","cuentas","proxy"],"prerequisite":["start-add-account","start-proxy-and-first-client"],"order":5},"headers":[],"relativePath":"es/lbjlaq/Antigravity-Manager/advanced/quota/index.md","filePath":"es/lbjlaq/Antigravity-Manager/advanced/quota/index.md"}'),n={name:"es/lbjlaq/Antigravity-Manager/advanced/quota/index.md"};function i(c,e,s,d,l,u){return t(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="gestion-de-cuotas-la-combinacion-de-quota-protection-smart-warmup" tabindex="-1">Gestión de cuotas: la combinación de Quota Protection + Smart Warmup <a class="header-anchor" href="#gestion-de-cuotas-la-combinacion-de-quota-protection-smart-warmup" aria-label="Permalink to &quot;Gestión de cuotas: la combinación de Quota Protection + Smart Warmup&quot;">​</a></h1><p>Usas Antigravity Tools para ejecutar el proxy de forma estable, pero lo que más temes es esto: la cuota de tu modelo principal se &quot;consume silenciosamente&quot;, y cuando realmente necesitas usarla, descubres que ya está demasiado baja para usar.</p><p>Este enfoque se centra en la <strong>gestión de cuotas</strong>: usa Quota Protection para reservar modelos clave; usa Smart Warmup para hacer un &quot;calentamiento ligero&quot; cuando la cuota se recupera al 100%, reduciendo fallos temporales.</p><h2 id="¿que-es-la-gestion-de-cuotas" tabindex="-1">¿Qué es la gestión de cuotas? <a class="header-anchor" href="#¿que-es-la-gestion-de-cuotas" aria-label="Permalink to &quot;¿Qué es la gestión de cuotas?&quot;">​</a></h2><p><strong>Gestión de cuotas</strong> significa usar dos mecanismos interconectados en Antigravity Tools para controlar &quot;cómo gastar la cuota&quot;: cuando la cuota restante de un modelo cae por debajo del umbral, Quota Protection agregará ese modelo a <code>protected_models</code> de la cuenta, y las solicitudes a ese modelo se evitarán primero; cuando la cuota vuelva al 100%, Smart Warmup activará una solicitud de calentamiento con tráfico mínimo y usará el archivo de historial local para un enfriamiento de 4 horas.</p><h2 id="que-puedes-hacer-al-finalizar" tabindex="-1">Qué puedes hacer al finalizar <a class="header-anchor" href="#que-puedes-hacer-al-finalizar" aria-label="Permalink to &quot;Qué puedes hacer al finalizar&quot;">​</a></h2><ul><li>Habilitar Quota Protection para que las cuentas con cuota baja &quot;cedan el paso&quot; automáticamente, reservando modelos de alto valor para solicitudes críticas</li><li>Habilitar Smart Warmup para calentamiento automático cuando la cuota se recupere (y comprender cómo el enfriamiento de 4 horas afecta la frecuencia de activación)</li><li>Comprender dónde actúan los tres campos <code>quota_protection</code> / <code>scheduled_warmup</code> / <code>protected_models</code></li><li>Conocer qué nombres de modelo se normalizan en &quot;grupos protegidos&quot; (y cuáles no)</li></ul><h2 id="tu-situacion-actual" tabindex="-1">Tu situación actual <a class="header-anchor" href="#tu-situacion-actual" aria-label="Permalink to &quot;Tu situación actual&quot;">​</a></h2><ul><li>Crees que estás &quot;rotando cuentas&quot;, pero en realidad sigues consumiendo el mismo tipo de modelo de alto valor</li><li>Descubres que la cuota está baja solo cuando ya es demasiado tarde, o incluso Claude Code/el cliente consume la cuota en segundo plano con warmup</li><li>Habilitaste el calentamiento, pero no sabes cuándo se activa, si hay enfriamiento, o si afectará la cuota</li></ul><h2 id="cuando-usar-este-enfoque" tabindex="-1">Cuándo usar este enfoque <a class="header-anchor" href="#cuando-usar-este-enfoque" aria-label="Permalink to &quot;Cuándo usar este enfoque&quot;">​</a></h2><ul><li>Tienes un pool de múltiples cuentas y deseas que los modelos clave tengan &quot;reservas&quot; para &quot;momentos importantes&quot;</li><li>No quieres monitorear manualmente cuándo la cuota se recupera al 100%, prefieres que el sistema haga automáticamente una &quot;verificación ligera tras la recuperación&quot;</li></ul><h2 id="🎒-preparativos-antes-de-comenzar" tabindex="-1">🎒 Preparativos antes de comenzar <a class="header-anchor" href="#🎒-preparativos-antes-de-comenzar" aria-label="Permalink to &quot;🎒 Preparativos antes de comenzar&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Requisitos previos</p><p>Este enfoque asume que ya puedes:</p><ul><li>Ver la lista de cuentas en la página <strong>Accounts</strong> y actualizar manualmente las cuotas</li><li>Haber iniciado el proxy inverso local (al menos poder acceder a <code>/healthz</code>)</li></ul><p>Si aún no funciona, primero lee <strong><a href="/docs/opencodedocs/es/lbjlaq/Antigravity-Manager/start/proxy-and-first-client/">Iniciar el proxy inverso local y conectar el primer cliente</a></strong>.</p></div><p>Además, Smart Warmup escribirá un archivo de historial local <code>warmup_history.json</code>. Se guarda en el directorio de datos; primero puedes leer <strong><a href="/docs/opencodedocs/es/lbjlaq/Antigravity-Manager/start/first-run-data/">Primera ejecución: directorio de datos, registros, bandeja y inicio automático</a></strong> para conocer la ubicación y la forma de respaldar el directorio de datos.</p><h2 id="idea-central" tabindex="-1">Idea central <a class="header-anchor" href="#idea-central" aria-label="Permalink to &quot;Idea central&quot;">​</a></h2><p>Detrás de esta &quot;combinación&quot; hay una lógica simple:</p><ul><li>Quota Protection es responsable de &quot;no seguir desperdiciando&quot;: cuando un modelo está por debajo del umbral, se marca como protegido, y las solicitudes a ese modelo se evitarán primero (a nivel de modelo, no deshabilitando la cuenta por completo).</li><li>Smart Warmup es responsable de &quot;verificar cuando la cuota se recupere&quot;: cuando el modelo vuelve al 100%, activa una solicitud ligera para confirmar que la ruta está disponible, y usa un enfriamiento de 4 horas para evitar interrupciones repetidas.</li></ul><p>Los campos de configuración correspondientes están en <code>AppConfig</code> del frontend:</p><ul><li><code>quota_protection.enabled / threshold_percentage / monitored_models</code> (ver <code>src/types/config.ts</code>)</li><li><code>scheduled_warmup.enabled / monitored_models</code> (ver <code>src/types/config.ts</code>)</li></ul><p>La lógica que realmente decide &quot;si omitir esta cuenta al solicitar este modelo&quot; está en TokenManager del backend:</p><ul><li><code>protected_models</code> del archivo de cuenta participará en el filtrado en <code>get_token(..., target_model)</code> (ver <code>src-tauri/src/proxy/token_manager.rs</code>)</li><li><code>target_model</code> se normaliza primero (<code>normalize_to_standard_id</code>), por lo que variantes como <code>claude-sonnet-4-5-thinking</code> se agrupan en el mismo &quot;grupo protegido&quot; (ver <code>src-tauri/src/proxy/common/model_mapping.rs</code>)</li></ul><h2 id="proximo-capitulo" tabindex="-1">Próximo capítulo <a class="header-anchor" href="#proximo-capitulo" aria-label="Permalink to &quot;Próximo capítulo&quot;">​</a></h2><blockquote><p>En el próximo capítulo aprenderemos <strong><a href="/docs/opencodedocs/es/lbjlaq/Antigravity-Manager/advanced/monitoring/">Proxy Monitor: registros de solicitudes, filtrado, restauración de detalles y exportación</a></strong>, convirtiendo la caja negra de llamadas en una cadena de evidencia revisable.</p></blockquote><h2 id="sigueme" tabindex="-1">Sígueme <a class="header-anchor" href="#sigueme" aria-label="Permalink to &quot;Sígueme&quot;">​</a></h2><h3 id="paso-1-primero-actualiza-la-cuota-para-tener-numeros-claros" tabindex="-1">Paso 1: primero actualiza la cuota para &quot;tener números claros&quot; <a class="header-anchor" href="#paso-1-primero-actualiza-la-cuota-para-tener-numeros-claros" aria-label="Permalink to &quot;Paso 1: primero actualiza la cuota para &quot;tener números claros&quot;&quot;">​</a></h3><p><strong>Por qué</strong> Quota Protection se basa en <code>quota.models[].percentage</code> de la cuenta para tomar decisiones. Si no has actualizado la cuota, la lógica de protección no puede hacer nada por ti.</p><p>Ruta: abre la página <strong>Accounts</strong>, haz clic en el botón de actualizar en la barra de herramientas (puedes actualizar una sola cuenta o todas).</p><p><strong>Deberías ver</strong>: aparece el porcentaje de cuota para cada modelo en la fila de la cuenta (por ejemplo, 0-100) y el reset time.</p><h3 id="paso-2-habilita-smart-warmup-en-settings-opcional-pero-recomendado" tabindex="-1">Paso 2: habilita Smart Warmup en Settings (opcional, pero recomendado) <a class="header-anchor" href="#paso-2-habilita-smart-warmup-en-settings-opcional-pero-recomendado" aria-label="Permalink to &quot;Paso 2: habilita Smart Warmup en Settings (opcional, pero recomendado)&quot;">​</a></h3><p><strong>Por qué</strong> El objetivo de Smart Warmup no es &quot;ahorrar cuota&quot;, sino &quot;auto-verificar la ruta cuando la cuota se recupere&quot;. Solo se activa cuando la cuota del modelo llega al 100%, y tiene un enfriamiento de 4 horas.</p><p>Ruta: entra en <strong>Settings</strong>, cambia al área de configuración relacionada con cuentas, habilita el interruptor <strong>Smart Warmup</strong>, y marca los modelos que deseas monitorear.</p><p>No olvides guardar la configuración.</p><p><strong>Deberías ver</strong>: al expandir Smart Warmup aparece una lista de modelos; al menos 1 modelo debe permanecer marcado.</p><h3 id="paso-3-habilita-quota-protection-y-establece-el-umbral-y-los-modelos-monitoreados" tabindex="-1">Paso 3: habilita Quota Protection, y establece el umbral y los modelos monitoreados <a class="header-anchor" href="#paso-3-habilita-quota-protection-y-establece-el-umbral-y-los-modelos-monitoreados" aria-label="Permalink to &quot;Paso 3: habilita Quota Protection, y establece el umbral y los modelos monitoreados&quot;">​</a></h3><p><strong>Por qué</strong> Quota Protection es el núcleo de &quot;reservar&quot;: cuando el porcentaje de cuota de los modelos monitoreados es <code>&lt;= threshold_percentage</code>, escribirá ese modelo en <code>protected_models</code> del archivo de cuenta, y las solicitudes posteriores a ese modelo evitarán primero este tipo de cuentas.</p><p>Ruta: en <strong>Settings</strong>, habilita <strong>Quota Protection</strong>.</p><ol><li>Establece el umbral (<code>1-99</code>)</li><li>Marca los modelos que deseas monitorear (al menos 1)</li></ol><div class="tip custom-block"><p class="custom-block-title">Una configuración inicial muy útil</p><p>Si no quieres complicarte, empieza con <code>threshold_percentage=10</code> predeterminado (ver <code>src/pages/Settings.tsx</code>).</p></div><p><strong>Deberías ver</strong>: al menos 1 modelo debe permanecer marcado en Quota Protection (la interfaz te impedirá quitar el último).</p><h3 id="paso-4-confirma-que-la-normalizacion-de-grupos-protegidos-no-te-causara-problemas" tabindex="-1">Paso 4: confirma que la &quot;normalización de grupos protegidos&quot; no te causará problemas <a class="header-anchor" href="#paso-4-confirma-que-la-normalizacion-de-grupos-protegidos-no-te-causara-problemas" aria-label="Permalink to &quot;Paso 4: confirma que la &quot;normalización de grupos protegidos&quot; no te causará problemas&quot;">​</a></h3><p><strong>Por qué</strong> Cuando TokenManager realiza el juicio de protección de cuota, primero normalizará <code>target_model</code> a un ID estándar (<code>normalize_to_standard_id</code>). Por ejemplo, <code>claude-sonnet-4-5-thinking</code> se normalizará a <code>claude-sonnet-4-5</code>.</p><p>Esto significa:</p><ul><li>Marcas <code>claude-sonnet-4-5</code> en Quota Protection</li><li>Cuando realmente solicitas <code>claude-sonnet-4-5-thinking</code></li></ul><p>Aún se activará la protección (porque pertenecen al mismo grupo).</p><p><strong>Deberías ver</strong>: cuando <code>protected_models</code> de una cuenta contiene <code>claude-sonnet-4-5</code>, las solicitudes a <code>claude-sonnet-4-5-thinking</code> evitarán primero esa cuenta.</p><h3 id="paso-5-cuando-necesites-verificar-de-inmediato-usa-calentamiento-manual-para-activar-un-warmup" tabindex="-1">Paso 5: cuando necesites verificar de inmediato, usa &quot;calentamiento manual&quot; para activar un warmup <a class="header-anchor" href="#paso-5-cuando-necesites-verificar-de-inmediato-usa-calentamiento-manual-para-activar-un-warmup" aria-label="Permalink to &quot;Paso 5: cuando necesites verificar de inmediato, usa &quot;calentamiento manual&quot; para activar un warmup&quot;">​</a></h3><p><strong>Por qué</strong> El ciclo de escaneo de Smart Warmup programado es cada 10 minutos (ver <code>src-tauri/src/modules/scheduler.rs</code>). Si quieres verificar la ruta de inmediato, el calentamiento manual es más directo.</p><p>Ruta: abre la página <strong>Accounts</strong>, haz clic en el botón &quot;Warmup&quot; en la barra de herramientas:</p><ul><li>Sin seleccionar cuentas: activa warmup completo (llama a <code>warm_up_all_accounts</code>)</li><li>Con cuentas seleccionadas: activa warmup para cada cuenta seleccionada (llama a <code>warm_up_account</code>)</li></ul><p><strong>Deberías ver</strong>: aparece un toast, el contenido proviene de la cadena devuelta por el backend (por ejemplo, &quot;Warmup task triggered ...&quot;).</p><h2 id="puntos-de-verificacion-✅" tabindex="-1">Puntos de verificación ✅ <a class="header-anchor" href="#puntos-de-verificacion-✅" aria-label="Permalink to &quot;Puntos de verificación ✅&quot;">​</a></h2><ul><li>Puedes ver el porcentaje de cuota del modelo de cada cuenta en la página Accounts (demostrando que la cadena de datos de cuota está OK)</li><li>Puedes habilitar Quota Protection / Smart Warmup en Settings y guardar la configuración con éxito</li><li>Comprendes que <code>protected_models</code> es una restricción &quot;a nivel de modelo&quot;: una cuenta puede evitarse solo para ciertos modelos</li><li>Sabes que warmup tiene un enfriamiento de 4 horas: repetir clics de calentamiento en poco tiempo puede ver indicaciones relacionadas con &quot;skipped/cooldown&quot;</li></ul><h2 id="advertencias-sobre-problemas-comunes" tabindex="-1">Advertencias sobre problemas comunes <a class="header-anchor" href="#advertencias-sobre-problemas-comunes" aria-label="Permalink to &quot;Advertencias sobre problemas comunes&quot;">​</a></h2><h3 id="_1-habilitaste-quota-protection-pero-nunca-se-activo" tabindex="-1">1) Habilitaste Quota Protection, pero nunca se activó <a class="header-anchor" href="#_1-habilitaste-quota-protection-pero-nunca-se-activo" aria-label="Permalink to &quot;1) Habilitaste Quota Protection, pero nunca se activó&quot;">​</a></h3><p>La causa más común es: la cuenta no tiene datos de <code>quota</code>. La lógica de protección en el backend necesita leer primero <code>quota.models[]</code> para poder juzgar el umbral (ver <code>src-tauri/src/proxy/token_manager.rs</code>).</p><p>Puedes volver al <strong>Paso 1</strong> y actualizar primero la cuota.</p><h3 id="_2-¿por-que-solo-algunos-modelos-se-consideran-grupos-protegidos" tabindex="-1">2) ¿Por qué solo algunos modelos se consideran &quot;grupos protegidos&quot;? <a class="header-anchor" href="#_2-¿por-que-solo-algunos-modelos-se-consideran-grupos-protegidos" aria-label="Permalink to &quot;2) ¿Por qué solo algunos modelos se consideran &quot;grupos protegidos&quot;?&quot;">​</a></h3><p>La normalización de <code>target_model</code> por TokenManager es de &quot;lista blanca&quot;: solo los nombres de modelo explícitamente listados se asignarán a ID estándar (ver <code>src-tauri/src/proxy/common/model_mapping.rs</code>).</p><p>La lógica después de la normalización es: usar el nombre normalizado (ID estándar o nombre de modelo original) para hacer coincidir el campo <code>protected_models</code> de la cuenta. Si la coincidencia es exitosa, la cuenta se omitirá (ver <code>src-tauri/src/proxy/token_manager.rs:555-560, 716-719</code>). Esto significa:</p><ul><li>Los modelos dentro de la lista blanca (como <code>claude-sonnet-4-5-thinking</code>) se normalizarán a ID estándar (<code>claude-sonnet-4-5</code>), y luego se juzgará si están en <code>protected_models</code></li><li>Cuando la normalización de modelos fuera de la lista blanca falla, retrocede al nombre de modelo original, y aún intentará hacer coincidir <code>protected_models</code></li></ul><p>En otras palabras, el juicio de protección de cuota es efectivo para &quot;todos los nombres de modelo&quot;, solo que los modelos dentro de la lista blanca se normalizan primero.</p><h3 id="_3-¿por-que-el-calentamiento-manual-programado-necesita-que-el-proxy-este-ejecutandose" tabindex="-1">3) ¿Por qué el calentamiento manual/programado necesita que el proxy esté ejecutándose? <a class="header-anchor" href="#_3-¿por-que-el-calentamiento-manual-programado-necesita-que-el-proxy-este-ejecutandose" aria-label="Permalink to &quot;3) ¿Por qué el calentamiento manual/programado necesita que el proxy esté ejecutándose?&quot;">​</a></h3><p>Las solicitudes de calentamiento finalmente llegarán al endpoint interno del proxy local: <code>POST /internal/warmup</code> (ver la ruta en <code>src-tauri/src/proxy/server.rs</code> y la implementación en <code>src-tauri/src/proxy/handlers/warmup.rs</code>). Si no has iniciado el servicio de proxy, warmup fallará.</p><p>Además, el puerto usado para calentamiento proviene de la configuración: <code>proxy.port</code> (si la lectura de configuración falla, retrocederá a <code>8045</code>, ver <code>src-tauri/src/modules/quota.rs</code>).</p><h2 id="resumen-de-esta-leccion" tabindex="-1">Resumen de esta lección <a class="header-anchor" href="#resumen-de-esta-leccion" aria-label="Permalink to &quot;Resumen de esta lección&quot;">​</a></h2><ul><li>Quota Protection hace &quot;recortar pérdidas&quot;: cuando está por debajo del umbral, escribe el modelo en <code>protected_models</code>, y al solicitar ese modelo se evita primero</li><li>Smart Warmup hace &quot;auto-verificación tras recuperación&quot;: solo se activa al 100%, escanea cada 10 minutos, con enfriamiento de 4 horas</li><li>Ambos dependen de la cadena de &quot;actualización de cuota&quot;: primero debe haber <code>quota.models[]</code>, la gestión tiene fundamento</li></ul><h2 id="proximo-capitulo-1" tabindex="-1">Próximo capítulo <a class="header-anchor" href="#proximo-capitulo-1" aria-label="Permalink to &quot;Próximo capítulo&quot;">​</a></h2><p>La gestión de cuotas resuelve &quot;cómo gastar de forma más estable&quot;. El próximo capítulo sugiere continuar con <strong>Proxy Monitor</strong>, convirtiendo los registros de solicitudes, la coincidencia de cuentas y el mapeo de modelos en una cadena de evidencia reproducible.</p><hr><h2 id="apendice-referencia-de-codigo-fuente" tabindex="-1">Apéndice: Referencia de código fuente <a class="header-anchor" href="#apendice-referencia-de-codigo-fuente" aria-label="Permalink to &quot;Apéndice: Referencia de código fuente&quot;">​</a></h2><details><summary><strong>Haz clic para expandir y ver las ubicaciones del código fuente</strong></summary><blockquote><p>Fecha de actualización: 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Función</th><th>Ruta del archivo</th><th>Línea</th></tr></thead><tbody><tr><td>UI de Quota Protection (umbral, selección de modelos, al menos 1)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/components/settings/QuotaProtection.tsx#L13-L168" target="_blank" rel="noreferrer"><code>src/components/settings/QuotaProtection.tsx</code></a></td><td>13-168</td></tr><tr><td>UI de Smart Warmup (marcado predeterminado al habilitar, al menos 1)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/components/settings/SmartWarmup.tsx#L14-L120" target="_blank" rel="noreferrer"><code>src/components/settings/SmartWarmup.tsx</code></a></td><td>14-120</td></tr><tr><td>Campos de configuración de gestión de cuotas (<code>quota_protection</code> / <code>scheduled_warmup</code>)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/types/config.ts#L54-L94" target="_blank" rel="noreferrer"><code>src/types/config.ts</code></a></td><td>54-94</td></tr><tr><td>Umbral predeterminado y configuración predeterminada (<code>threshold_percentage: 10</code>)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/pages/Settings.tsx#L20-L51" target="_blank" rel="noreferrer"><code>src/pages/Settings.tsx</code></a></td><td>20-51</td></tr><tr><td>Escribir/restaurar <code>protected_models</code> (juicio de umbral y persistencia)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/token_manager.rs#L254-L467" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/token_manager.rs</code></a></td><td>254-467</td></tr><tr><td>Filtrado de protección de cuotas del lado de solicitudes (<code>get_token(..., target_model)</code>)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/token_manager.rs#L470-L674" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/token_manager.rs</code></a></td><td>470-674</td></tr><tr><td>Normalización de grupos protegidos (<code>normalize_to_standard_id</code>)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/common/model_mapping.rs#L230-L254" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/common/model_mapping.rs</code></a></td><td>230-254</td></tr><tr><td>Escaneo programado de Smart Warmup (cada 10 minutos + enfriamiento de 4 horas + <code>warmup_history.json</code>)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/scheduler.rs#L11-L221" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/scheduler.rs</code></a></td><td>11-221</td></tr><tr><td>Comandos de calentamiento manual (<code>warm_up_all_accounts</code> / <code>warm_up_account</code>)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/commands/mod.rs#L167-L212" target="_blank" rel="noreferrer"><code>src-tauri/src/commands/mod.rs</code></a></td><td>167-212</td></tr><tr><td>Implementación de calentamiento (llama al endpoint interno <code>/internal/warmup</code>)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/quota.rs#L271-L512" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/quota.rs</code></a></td><td>271-512</td></tr><tr><td>Implementación del endpoint interno de calentamiento (construir solicitud + llamar upstream)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/warmup.rs#L3-L220" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/warmup.rs</code></a></td><td>3-220</td></tr></tbody></table></details>',71)])])}const g=a(n,[["render",i]]);export{p as __pageData,g as default};
